            SDAI.AIE(SDAI.STRING("AP242_MANAGED_MODEL_BASED_3D_ENGINEERING_MIM_LF.CURVE_REPLICA")) ] 
            as [SDAI.AggregationInitializerElement<SDAI.STRING>]) 
        let _TEMP3 /* SDAI.SET<SDAI.STRING>? */ = SDAI.FORCE_OPTIONAL(_TEMP1) * SDAI.FORCE_OPTIONAL(_TEMP2)
        let _TEMP4 /* SDAI.INTEGER? */ = SDAI.SIZEOF( _TEMP3 )
        let _TEMP5 /* SDAI.LOGICAL */ = _TEMP4 .==. SDAI.FORCE_OPTIONAL(SDAI.INTEGER(0))
        return _TEMP5
      }

      //EXPRESS IMPLICIT PARTIAL ENTITY CONSTRUCTOR
      /// initialize from explicit attribute values
      public init(
        USING_SKETCH: ePOSITIONED_SKETCH.PRef, 
        COMPUTED_REPRESENTATION: eCURVE.PRef
      ) {

        self._using_sketch = USING_SKETCH
        self._computed_representation = COMPUTED_REPRESENTATION

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( USING_SKETCH: original._using_sketch, COMPUTED_REPRESENTATION: original._computed_representation )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 2
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: ePOSITIONED_SKETCH.PRef.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]USING_SKETCH for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverRequiredParameter(as: eCURVE.PRef.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]COMPUTED_REPRESENTATION for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( USING_SKETCH: p0, COMPUTED_REPRESENTATION: p1 )
      }
    }
